from typing import Tuple, List

def executeCommand() -> Tuple[int, str, str]:
    """
    Read a command from user input, validate it, and execute it safely.

    Returns:
        tuple: (return_code, stdout, stderr)
    """
    # Define allowed commands (whitelist approach)
    ALLOWED_COMMANDS = {
        'ls', 'pwd', 'date', 'whoami', 'echo', 'cat', 'head', 'tail',
        'grep', 'wc', 'sort', 'uniq', 'find', 'which', 'whereis'
    }

    # Get user input
    try:
        command_input = input("Enter command to execute: ").strip()
    except (EOFError, KeyboardInterrupt):
        print("\nOperation cancelled.")
        return (-1, "", "User cancelled")

    if not command_input:
        return (-1, "", "Empty command")

    # Parse the command safely
    try:
        args = shlex.split(command_input)
    except ValueError as e:
        return (-1, "", f"Invalid command syntax: {e}")

    if not args:
        return (-1, "", "Empty command after parsing")

    # Validate the command
    command = args[0]

    # Check if command is in allowed list
    if command not in ALLOWED_COMMANDS:
        return (-1, "", f"Command '{command}' is not allowed")

    # Additional validation for specific commands
    if command == 'cat':
        # Limit cat to specific safe directories
        if len(args) > 1:
            for arg in args[1:]:
                if '..' in arg or arg.startswith('/'):
                    return (-1, "", "Path traversal not allowed")

    elif command == 'find':
        # Restrict find command parameters
        if '-exec' in args or ';' in args:
            return (-1, "", "find -exec not allowed")

    elif command == 'grep':
        # Prevent grep from reading sensitive files
        if len(args) > 2:
            for arg in args[2:]:
                if '/etc/' in arg or '/var/' in arg:
                    return (-1, "", "Access to system directories not allowed")

    # Execute the command safely
    try:
        result = subprocess.run(
            args,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=30,  # Prevent hanging
            check=False,
            shell=False  # Never use shell=True with user input
        )

        return (result.returncode, result.stdout, result.stderr)

    except subprocess.TimeoutExpired:
        return (-1, "", "Command timed out")
    except FileNotFoundError:
        return (-1, "", f"Command '{command}' not found")
    except Exception as e:
        return (-1, "", f"Error executing command: {str(e)}")

