import os
import socket
import paramiko


def downloadFile(hostname, username, password, sensitive_file):
    """
    Connect to an SFTP server using the hostname provided.
    Log-in using the username and password provided as parameters.
    Download to the current directory the sensitive file passed as parameter from the SFTP server.
    """
    # Input validation
    if not all(isinstance(param, str) for param in [hostname, username, password, sensitive_file]):
        raise TypeError("All parameters must be strings")

    if not hostname or not username or not password or not sensitive_file:
        raise ValueError("All parameters must be non-empty strings")

    # Validate filename to prevent path traversal
    if os.path.sep in sensitive_file or os.path.altsep and os.path.altsep in sensitive_file:
        raise ValueError("Invalid filename: path separators not allowed")

    if sensitive_file.startswith(('.', '..')):
        raise ValueError("Invalid filename: relative paths not allowed")

    ssh = None
    sftp = None
    try:
        # Create SSH client with timeout and secure host key policy
        ssh = paramiko.SSHClient()
        ssh.load_system_host_keys()
        ssh.set_missing_host_key_policy(paramiko.RejectPolicy())

        # Connect and login
        ssh.connect(hostname, username=username, password=password, timeout=30)

        # Open SFTP channel
        sftp = ssh.open_sftp()

        # Download file
        sftp.get(sensitive_file, sensitive_file)

    except socket.timeout:
        raise ConnectionError("Connection timeout")
    except paramiko.SSHException as e:
        raise ConnectionError(f"SFTP error: {str(e)}")
    except IOError as e:
        raise IOError(f"File operation error: {str(e)}")
    finally:
        if sftp:
            try:
                sftp.close()
            except:
                pass
        if ssh:
            try:
                ssh.close()
            except:
                pass

import re
from flask import request, Flask, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size

@app.route('/upload', methods=['POST'])
def upload():
    try:
        # Get username from form data
        username = request.form.get('username', '')

        # Validate username - only allow alphanumeric and underscore
        if not re.match(r'^[a-zA-Z0-9_]+$', username):
            return jsonify({'error': 'Invalid username format'}), 400

        # Get file from request
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400

        file = request.files['file']

        # Check if file was selected
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400

        # Secure the filename
        filename = secure_filename(file.filename)

        # Search for username in filename
        found = username in filename

        return jsonify({
            'username': username,
            'filename': filename,
            'username_in_filename': found
        })

    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(debug=False)

