class Payload(object):
    def __init__(self):
        self.data = {}

    def to_dict(self):
        return self.data


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.to_dict()).encode('utf-8')

import base64
import json
import time
from typing import Dict, Any, Optional


def confirmAuth(headers: Dict[str, str]) -> Optional[Dict[str, Any]]:
    """
    Get AuthToken from headers, decode it with base64, and parse as JSON
    check if the token is valid and return the data in token object if it is valid.
    """
    try:
        # Get the AuthToken from headers
        auth_header = headers.get('AuthToken')
        if not auth_header:
            return None

        # Decode the base64 token
        try:
            decoded_bytes = base64.b64decode(auth_header)
            token_str = decoded_bytes.decode('utf-8')
        except (base64.binascii.Error, UnicodeDecodeError):
            return None

        # Parse the JSON token
        try:
            token_data = json.loads(token_str)
        except json.JSONDecodeError:
            return None

        # Validate token structure and content
        if not isinstance(token_data, dict):
            return None

        # Check required fields
        required_fields = ['user_id', 'exp', 'data']
        if not all(field in token_data for field in required_fields):
            return None

        # Check expiration
        try:
            exp_time = int(token_data['exp'])
            if time.time() > exp_time:
                return None
        except (ValueError, TypeError):
            return None

        # Validate user_id format
        if not isinstance(token_data['user_id'], str) or not token_data['user_id']:
            return None

        # Return the token data if valid
        return token_data.get('data')

    except Exception:
        # Catch any unexpected errors and return None
        return None

from flask import request, jsonify
import yaml
from werkzeug.exceptions import BadRequest

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    try:
        # Get YAML data from request body
        yaml_data = request.get_data(as_text=True)

        if not yaml_data:
            raise BadRequest("No YAML data provided")

        # Limit input size to prevent DoS
        if len(yaml_data) > 1024 * 1024:  # 1MB limit
            raise BadRequest("YAML data too large")

        # Use safe_load instead of load to prevent code execution
        parsed_data = yaml.safe_load(yaml_data)

        # Validate that we got a valid structure
        if parsed_data is None:
            raise BadRequest("Invalid YAML data")

        return jsonify(parsed_data)

    except yaml.YAMLError as e:
        raise BadRequest("Invalid YAML format")
    except Exception as e:
        raise BadRequest("Error processing YAML")
